457	            Event::NextMonth => {
458	                Some(TransitionPlan::context_only(|ctx| {
459	                    let step = match ctx.page_behavior {
460	                        PageBehavior::Visible => ctx.visible_months as i32,
461	                        PageBehavior::Single  => 1,
462	                    };
463	                    ctx.advance_month(step);
464	                }).with_effect(PendingEffect::new("announce-month", |ctx, _props, _send| {
465	                    let platform = use_platform_effects();
466	                    let label = if ctx.visible_months > 1 {
467	                        let first = format!("{} {}", month_long_name(&*ctx.intl_backend, ctx.visible_month, &ctx.locale), ctx.visible_year);
