482	                        PageBehavior::Visible => ctx.visible_months as i32,
483	                        PageBehavior::Single  => 1,
484	                    };
485	                    ctx.advance_month(-step);
486	                }).with_effect(PendingEffect::new("announce-month", |ctx, _props, _send| {
487	                    let platform = use_platform_effects();
488	                    let label = if ctx.visible_months > 1 {
489	                        let first = format!("{} {}", month_long_name(&*ctx.intl_backend, ctx.visible_month, &ctx.locale), ctx.visible_year);
490	                        let (lm, ly) = ctx.month_year_at_offset(ctx.visible_months - 1);
