548	impl Machine {
549	    /// Keyboard navigation within the calendar grid.
550	    /// Follows WAI-ARIA Grid pattern with RTL awareness.
551	    fn handle_keydown(
552	        state: &State,
553	        data: &KeyboardEventData,
554	        ctx: &Context,
555	    ) -> Option<TransitionPlan<Self>> {
556	        // Only handle keys when the grid is focused.
557	        if *state != State::Focused { return None; }
558	
559	        let focused = ctx.focused_date.clone();
560	        // RTL-aware directional keys: in RTL, Left means "next" and Right means "prev".
561	        let (prev_day_key, next_day_key) = if ctx.is_rtl {
562	            (KeyboardKey::ArrowRight, KeyboardKey::ArrowLeft)
563	        } else {
564	            (KeyboardKey::ArrowLeft, KeyboardKey::ArrowRight)
565	        };
566	
567	        let new_focus = match data.key {
568	            k if k == prev_day_key => Some(focused.add_days(-1)),
569	            k if k == next_day_key => Some(focused.add_days(1)),
570	            KeyboardKey::ArrowUp              => Some(focused.add_days(-7)),
571	            KeyboardKey::ArrowDown            => Some(focused.add_days(7)),
572	            KeyboardKey::Home                 => {
573	                // Move to start of current week.
574	                let wd = focused.weekday() as u8;
575	                let start = ctx.first_day_of_week as u8;
576	                let offset = ((wd + 7 - start) % 7) as i32;
577	                Some(focused.add_days(-offset))
578	            }
579	            KeyboardKey::End => {
580	                // Move to end of current week.
581	                let wd = focused.weekday() as u8;
582	                let start = ctx.first_day_of_week as u8;
583	                let offset = ((wd + 7 - start) % 7) as i32;
584	                Some(focused.add_days(6 - offset))
585	            }
586	            KeyboardKey::PageUp  => Some(focused.add_months(-1)),
587	            KeyboardKey::PageDown => Some(focused.add_months(1)),
588	            _ => None,
589	        };
590	
591	        // Shift+PageUp/PageDown for year navigation is handled separately
592	        // because the key enum itself doesn't encode the shift modifier.
593	        // Adapters call `on_grid_keydown(data, shift)` which maps:
594	        //   Shift+PageUp   -> Event::PrevYear
595	        //   Shift+PageDown -> Event::NextYear
596	
597	        match new_focus {
598	            Some(date) => {
599	                let clamped = ctx.clamp_date(date);
600	                Some(TransitionPlan::to(State::Focused)
601	                    .apply(move |ctx| {
602	                        ctx.focused_date = clamped;
603	                        ctx.sync_visible_to_focused();
604	                    }))
605	            }
606	            None => {
607	                // Enter / Space selects the focused date.
608	                match data.key {
609	                    KeyboardKey::Enter | KeyboardKey::Space => {
610	                        let date = focused;
611	                        Some(TransitionPlan::context_only(|_ctx| {})
612	                            .then(Event::SelectDate { date }))
613	                    }
614	                    _ => None,
615	                }
616	            }
617	        }
618	    }
619	}
