//! Typed connect primitives used by component `connect()` APIs.
//!
//! This module defines the typed HTML attribute, DOM event, CSS property, and
//! attribute-map contracts used by the architecture specification. They provide
//! a framework-agnostic vocabulary for converting machine state into DOM-facing
//! metadata without relying on raw string literals throughout the codebase.

use alloc::{format, string::String, sync::Arc, vec::Vec};
use core::fmt::{self, Debug, Display};

/// Typed `aria-*` attribute names used by [`HtmlAttr::Aria`].
#[non_exhaustive]
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, PartialOrd, Ord)]
pub enum AriaAttr {
    /// `aria-activedescendant`
    ActiveDescendant,

    /// `aria-autocomplete`
    AutoComplete,

    /// `aria-checked`
    Checked,

    /// `aria-disabled`
    Disabled,

    /// `aria-errormessage`
    ErrorMessage,

    /// `aria-expanded`
    Expanded,

    /// `aria-haspopup`
    HasPopup,

    /// `aria-hidden`
    Hidden,

    /// `aria-invalid`
    Invalid,

    /// `aria-keyshortcuts`
    KeyShortcuts,

    /// `aria-label`
    Label,

    /// `aria-labelledby`
    LabelledBy,

    /// `aria-level`
    Level,

    /// `aria-modal`
    Modal,

    /// `aria-multiline`
    MultiLine,

    /// `aria-multiselectable`
    MultiSelectable,

    /// `aria-orientation`
    Orientation,

    /// `aria-placeholder`
    Placeholder,

    /// `aria-pressed`
    Pressed,

    /// `aria-readonly`
    ReadOnly,

    /// `aria-required`
    Required,

    /// `aria-roledescription`
    RoleDescription,

    /// `aria-selected`
    Selected,

    /// `aria-sort`
    Sort,

    /// `aria-valuemax`
    ValueMax,

    /// `aria-valuemin`
    ValueMin,

    /// `aria-valuenow`
    ValueNow,

    /// `aria-valuetext`
    ValueText,

    /// `aria-atomic`
    Atomic,

    /// `aria-busy`
    Busy,

    /// `aria-live`
    Live,

    /// `aria-relevant`
    Relevant,

    /// `aria-dropeffect`
    DropEffect,

    /// `aria-grabbed`
    Grabbed,

    /// `aria-colcount`
    ColCount,

    /// `aria-colindex`
    ColIndex,

    /// `aria-colspan`
    ColSpan,

    /// `aria-controls`
    Controls,

    /// `aria-current`
    Current,

    /// `aria-describedby`
    DescribedBy,

    /// `aria-description`
    Description,

    /// `aria-details`
    Details,

    /// `aria-flowto`
    FlowTo,

    /// `aria-owns`
    Owns,

    /// `aria-posinset`
    PosInSet,

    /// `aria-rowcount`
    RowCount,

    /// `aria-rowindex`
    RowIndex,

    /// `aria-rowspan`
    RowSpan,

    /// `aria-setsize`
    SetSize,
}

impl AriaAttr {
    /// Returns the HTML attribute spelling for this ARIA discriminant.
    #[must_use]
    pub const fn as_str(&self) -> &'static str {
        match self {
            Self::ActiveDescendant => "aria-activedescendant",
            Self::AutoComplete => "aria-autocomplete",
            Self::Checked => "aria-checked",
            Self::Disabled => "aria-disabled",
            Self::ErrorMessage => "aria-errormessage",
            Self::Expanded => "aria-expanded",
            Self::HasPopup => "aria-haspopup",
