fn with_field_bounds(
    generics: &Generics,
    field_types: &[Type],
    bounds: &[TokenStream],
) -> Generics {
    let mut generics = generics.clone();

    let where_clause = generics.make_where_clause();

    for field_ty in field_types {
        for bound in bounds {
            where_clause
                .predicates
                .push(parse_quote!(#field_ty: #bound));
        }
    }

    generics
