    pub fn is_empty(&self) -> bool {
        self.dates.is_empty()
    }

    /// Iterates over the selected dates in chronological order.
    pub fn iter(&self) -> core::slice::Iter<'_, CalendarDate> {
        self.dates.iter()
    }

    /// Returns whether `date` is in the set.
