1	//! Unit and snapshot tests for the `Calendar` component.
2	//!
3	//! Test names that begin with `snapshot_` use `insta::assert_snapshot!` and
4	//! commit golden output under `snapshots/`. Every other test is a pure
5	//! state-machine assertion that does not depend on `.snap` files.
6	
7	use alloc::{
8	    format,
9	    string::{String, ToString as _},
10	    sync::Arc,
11	    vec::Vec,
12	};
13	
14	use ars_core::{AttrMap, ComponentPart, Env, HtmlAttr, KeyboardKey, Service};
15	use ars_i18n::{
16	    CalendarDate, Locale, StubIntlBackend,
17	    locales::{ar_sa, de_de, en_gb, en_us, fa},
18	};
19	use insta::assert_snapshot;
20	
21	use super::*;
22	
23	// ────────────────────────────────────────────────────────────────────
24	// Helpers
25	// ────────────────────────────────────────────────────────────────────
26	
27	fn date(year: i32, month: u8, day: u8) -> CalendarDate {
28	    CalendarDate::new_gregorian(year, month, day).expect("valid test date")
29	}
30	
31	fn props() -> Props {
32	    Props::new().id("cal").today(date(2024, 1, 15))
33	}
34	
35	fn env(locale: Locale) -> Env {
36	    Env::new(locale, Arc::new(StubIntlBackend))
37	}
38	
39	fn service() -> Service<Machine> {
40	    Service::<Machine>::new(props(), &env(en_us()), &Messages::default())
41	}
42	
43	fn service_with(props: Props, locale: Locale) -> Service<Machine> {
44	    Service::<Machine>::new(props, &env(locale), &Messages::default())
45	}
46	
47	fn snapshot_attrs(attrs: &AttrMap) -> String {
48	    format!("{attrs:#?}")
49	}
50	
51	fn attr(attrs: &AttrMap, key: HtmlAttr) -> Option<String> {
52	    attrs.get(&key).map(ToString::to_string)
53	}
54	
55	// ────────────────────────────────────────────────────────────────────
56	// Initial state
57	// ────────────────────────────────────────────────────────────────────
58	
59	#[test]
60	fn initial_state_is_idle() {
61	    let svc = service();
62	    assert_eq!(*svc.state(), State::Idle);
63	}
64	
65	#[test]
66	fn initial_focused_date_falls_back_to_today() {
67	    let svc = service();
68	    assert_eq!(svc.context().focused_date, date(2024, 1, 15));
69	}
70	
71	#[test]
72	fn initial_focused_date_prefers_controlled_value() {
73	    let props = props().value(Some(date(2023, 7, 4)));
74	    let svc = service_with(props, en_us());
75	    assert_eq!(svc.context().focused_date, date(2023, 7, 4));
76	    assert_eq!(svc.context().visible_month, 7);
77	    assert_eq!(svc.context().visible_year, 2023);
78	}
79	
80	#[test]
81	fn focus_in_transitions_to_focused() {
82	    let mut svc = service();
83	    drop(svc.send(Event::FocusIn));
84	    assert_eq!(*svc.state(), State::Focused);
85	}
86	
87	#[test]
88	fn focus_out_returns_to_idle() {
89	    let mut svc = service();
90	    drop(svc.send(Event::FocusIn));
91	    drop(svc.send(Event::FocusOut));
92	    assert_eq!(*svc.state(), State::Idle);
93	}
94	
