    pub fn is_date_disabled(&self, date: &CalendarDate) -> bool {
        if self.disabled { return true; }
        if let Some(min) = &self.min
            && date.compare(min) == Ordering::Less
        {
            return true;
        }
        if let Some(max) = &self.max
            && date.compare(max) == Ordering::Greater
        {
            return true;
        }
        false
