            value: None,
            default_value: None,
            min: None,
            max: None,
            disabled: false,
            readonly: false,
            is_date_unavailable: None,
            first_day_of_week: None,
            show_week_numbers: false,
            is_rtl: false,
            visible_months: 1,
            page_behavior: PageBehavior::Visible,
            today: CalendarDate::new_gregorian(2025, nzu8(1), nzu8(1)),
        }
    }
