1	//! Grid math for the `Calendar` component.
2	//!
3	//! Pure functions over a small slice of the parent [`Context`] state: the
4	//! visible month/year, the configured first-day-of-week, and the visible
5	//! month count. The machine in [`super`] holds the full context and forwards
6	//! the relevant fields here so this module stays free of the wider machine
7	//! plumbing — useful both for unit testing the math in isolation and for
8	//! keeping the §1.6 spec algorithm legible alongside the rest of the
9	//! transitions.
10	
11	use alloc::vec::Vec;
12	
13	use ars_i18n::{CalendarDate, Weekday};
14	
15	/// Sunday-zero index for a weekday.
16	///
17	/// The spec's §1.6 grid algorithm uses modulo arithmetic that anchors at
18	/// Sunday=0, but [`Weekday`] is iso-numbered (Monday=1..Sunday=7). The local
19	/// helper isolates that conversion so every grid call site uses the same
20	/// convention.
21	#[must_use]
22	pub(super) const fn weekday_sunday_zero(weekday: Weekday) -> u8 {
23	    match weekday {
24	        Weekday::Sunday => 0,
25	        Weekday::Monday => 1,
26	        Weekday::Tuesday => 2,
27	        Weekday::Wednesday => 3,
28	        Weekday::Thursday => 4,
29	        Weekday::Friday => 5,
30	        Weekday::Saturday => 6,
31	    }
32	}
33	
34	/// Returns `(month, year)` for the month at `offset` from the first visible
35	/// month, normalising the result to the 1..=12 month range with a year
36	/// adjustment.
37	#[must_use]
38	pub(super) const fn month_year_at_offset(
39	    visible_month: u8,
40	    visible_year: i32,
41	    offset: usize,
42	) -> (u8, i32) {
43	    let raw_index = visible_month as i64 - 1 + offset as i64;
44	
45	    let normalised_month = raw_index.rem_euclid(12) as u8 + 1;
46	    let year_delta = raw_index.div_euclid(12) as i32;
47	
48	    (normalised_month, visible_year + year_delta)
49	}
50	
51	/// Advances `(month, year)` by `n` months (signed), normalising the month
52	/// back into the 1..=12 range.
53	#[must_use]
54	pub(super) const fn advance_month(visible_month: u8, visible_year: i32, n: i32) -> (u8, i32) {
55	    let raw_index = visible_month as i64 - 1 + n as i64;
56	
57	    let normalised_month = raw_index.rem_euclid(12) as u8 + 1;
58	    let year_delta = raw_index.div_euclid(12) as i32;
59	
60	    (normalised_month, visible_year + year_delta)
61	}
62	
63	/// Builds the 6-week grid for the month at the supplied offset.
64	///
65	/// Always returns exactly 6 rows of 7 dates each (42 cells), padded with
66	/// leading days from the previous month and trailing days from the next.
67	/// The leading-day count is derived from the difference between the first
68	/// day of the target month and the configured `first_day_of_week`, modulo 7.
69	///
70	/// Date arithmetic at the start/end of the supported calendar range
71	/// (`new_gregorian` reject) is treated as a no-op: the returned vector is
72	/// empty in that case, signalling that the adapter should render an empty
73	/// grid for the boundary month rather than panic.
74	#[must_use]
75	pub(super) fn weeks_for(
76	    visible_month: u8,
77	    visible_year: i32,
78	    first_day_of_week: Weekday,
79	    offset: usize,
80	) -> Vec<[CalendarDate; 7]> {
81	    let (target_month, target_year) = month_year_at_offset(visible_month, visible_year, offset);
82	
83	    let Ok(first_of_month) = CalendarDate::new_gregorian(target_year, target_month, 1) else {
84	        return Vec::new();
85	    };
86	
87	    let first_weekday_index = weekday_sunday_zero(first_of_month.weekday());
88	    let start_index = weekday_sunday_zero(first_day_of_week);
89	
90	    let leading = i32::from((first_weekday_index + 7 - start_index) % 7);
91	
92	    let Ok(grid_start) = first_of_month.add_days(-leading) else {
93	        return Vec::new();
94	    };
95	
96	    let mut weeks: Vec<[CalendarDate; 7]> = Vec::with_capacity(6);
97	
98	    let mut current = grid_start;
99	
100	    for _ in 0..6 {
101	        let Some(row) = build_week(&current) else {
102	            return weeks;
103	        };
104	
105	        weeks.push(row);
106	
107	        let Ok(next_week_start) = current.add_days(7) else {
108	            return weeks;
109	        };
110	
111	        current = next_week_start;
112	    }
113	
114	    weeks
115	}
116	
117	fn build_week(start: &CalendarDate) -> Option<[CalendarDate; 7]> {
118	    let day0 = start.clone();
119	    let day1 = start.add_days(1).ok()?;
120	    let day2 = start.add_days(2).ok()?;
121	    let day3 = start.add_days(3).ok()?;
122	    let day4 = start.add_days(4).ok()?;
123	    let day5 = start.add_days(5).ok()?;
124	    let day6 = start.add_days(6).ok()?;
125	
126	    Some([day0, day1, day2, day3, day4, day5, day6])
127	}
128	
129	/// Whether `date` belongs to a different `(month, year)` than the month at
130	/// the given visible-month offset.
131	#[must_use]
132	pub(super) const fn is_outside_month_at_offset(
133	    date: &CalendarDate,
134	    visible_month: u8,
135	    visible_year: i32,
136	    offset: usize,
137	) -> bool {
138	    let (target_month, target_year) = month_year_at_offset(visible_month, visible_year, offset);
139	
140	    date.month() != target_month || date.year() != target_year
141	}
142	
143	/// Whether `date` falls within any of the `visible_months` months starting
144	/// at `(visible_month, visible_year)`.
145	#[must_use]
146	pub(super) fn is_in_visible_range(
147	    date: &CalendarDate,
148	    visible_month: u8,
149	    visible_year: i32,
150	    visible_months: usize,
151	) -> bool {
152	    (0..visible_months).any(|offset| {
153	        let (month, year) = month_year_at_offset(visible_month, visible_year, offset);
154	
155	        date.month() == month && date.year() == year
156	    })
157	}
158	
159	/// Ordered weekday sequence starting at `first_day_of_week`, returned as
160	/// `(weekday, sunday_zero_index)` pairs so callers can fetch labels from the
161	/// `IntlBackend` without re-deriving the index.
162	#[must_use]
163	pub(super) fn ordered_weekdays(first_day_of_week: Weekday) -> [Weekday; 7] {
164	    let start = weekday_sunday_zero(first_day_of_week);
165	
166	    let mut out = [Weekday::Sunday; 7];
167	
168	    for (i, slot) in out.iter_mut().enumerate() {
169	        *slot = sunday_zero_to_weekday((start + i as u8) % 7);
170	    }
171	
172	    out
173	}
174	
175	const fn sunday_zero_to_weekday(index: u8) -> Weekday {
176	    match index % 7 {
177	        0 => Weekday::Sunday,
178	        1 => Weekday::Monday,
179	        2 => Weekday::Tuesday,
180	        3 => Weekday::Wednesday,
181	        4 => Weekday::Thursday,
182	        5 => Weekday::Friday,
183	        _ => Weekday::Saturday,
184	    }
185	}
186	
187	#[cfg(test)]
188	mod tests {
189	    use super::*;
190	
191	    #[test]
192	    fn month_year_offset_within_same_year() {
193	        assert_eq!(month_year_at_offset(1, 2024, 0), (1, 2024));
194	        assert_eq!(month_year_at_offset(1, 2024, 2), (3, 2024));
195	        assert_eq!(month_year_at_offset(10, 2024, 1), (11, 2024));
196	    }
197	
198	    #[test]
199	    fn month_year_offset_wraps_into_next_year() {
200	        assert_eq!(month_year_at_offset(11, 2024, 2), (1, 2025));
201	        assert_eq!(month_year_at_offset(12, 2024, 1), (1, 2025));
202	    }
203	
204	    #[test]
205	    fn advance_month_handles_negative_into_prev_year() {
206	        assert_eq!(advance_month(1, 2024, -1), (12, 2023));
207	        assert_eq!(advance_month(3, 2024, -12), (3, 2023));
208	        assert_eq!(advance_month(6, 2024, 12), (6, 2025));
209	    }
210	
211	    #[test]
212	    fn weeks_for_january_2024_sunday_start_has_leading_days_from_december() {
213	        let weeks = weeks_for(1, 2024, Weekday::Sunday, 0);
214	
215	        assert_eq!(weeks.len(), 6);
216	
217	        // January 1, 2024 is a Monday, so with Sunday-start the first row
218	        // starts on December 31, 2023.
219	        let first = &weeks[0][0];
220	
221	        assert_eq!(first.year(), 2023);
222	        assert_eq!(first.month(), 12);
223	        assert_eq!(first.day(), 31);
224	
225	        // Second cell is January 1, 2024.
226	        let second = &weeks[0][1];
227	
228	        assert_eq!(second.year(), 2024);

