fn callback_new_ref_invokes_higher_ranked_closure() {
    let cb: Callback<dyn for<'a> Fn(&'a str) -> usize + Send + Sync> =
        Callback::new_ref(|s: &str| s.len());

    assert_eq!(cb("hello"), 5);

