1	//! Shared callback wrapper for event handler closures.
2	//!
3	//! [`Callback`] wraps closures in [`Arc`](alloc::sync::Arc) so they can be
4	//! stored in Props structs, cloned cheaply, and
5	//! compared by pointer identity. `Clone`, `PartialEq`, `Deref`, and `AsRef`
6	//! all delegate to `Arc` with no cfg-gated code.
7	//!
8	//! ## Thread-safety
9	//!
10	//! All public constructors (`new`, `new_void`, `From`, [`callback`]) require
11	//! `Send + Sync` bounds on the wrapped closure, and the trait objects in the
12	//! type signatures (`dyn Fn(...) + Send + Sync`) carry those bounds so
13	//! `Callback<…>` is itself `Send + Sync`. This is necessary for adapter
14	//! crates whose framework requires cleanup/effect closures to be
15	//! thread-safe (e.g. Leptos's `on_cleanup`).
16	
17	use alloc::sync::Arc;
18	use core::{
19	    fmt::{self, Debug},
20	    ops::Deref,
21	};
22	
23	/// Shared callback wrapper for event handler closures in Props structs.
24	///
25	/// Wraps closures in [`Arc`] (`Arc`) on every target. This is distinct from
26	/// [`MessageFn`](crate::MessageFn) (used for i18n message closures) and
27	/// [`CleanupFn`](crate::CleanupFn) (used for effect cleanup).
28	///
29	/// Supports an optional return type via
30	/// `Callback<dyn Fn(Args) -> Out + Send + Sync>`. When the return type is
31	/// `()`, write `Callback<dyn Fn(Args) + Send + Sync>` as shorthand.
32	///
33	/// The trait object always carries `+ Send + Sync` so `Callback<T>` is
34	/// itself `Send + Sync`. All public constructors enforce that bound on the
35	/// closure being wrapped.
36	pub struct Callback<T: ?Sized>(pub(crate) Arc<T>);
37	
38	impl<T: ?Sized> Clone for Callback<T> {
39	    fn clone(&self) -> Self {
40	        Callback(Arc::clone(&self.0))
41	    }
42	}
43	
44	impl<T: ?Sized> Debug for Callback<T> {
45	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
46	        f.write_str("Callback(..)")
47	    }
48	}
49	
50	impl<T: ?Sized> PartialEq for Callback<T> {
51	    fn eq(&self, other: &Self) -> bool {
52	        Arc::ptr_eq(&self.0, &other.0)
53	    }
54	}
55	
56	impl<T: ?Sized> Deref for Callback<T> {
57	    type Target = T;
58	
59	    fn deref(&self) -> &T {
60	        &self.0
61	    }
62	}
63	
64	impl<T: ?Sized> AsRef<T> for Callback<T> {
65	    fn as_ref(&self) -> &T {
66	        self.0.as_ref()
67	    }
68	}
69	
70	// ── Constructors for Callback<dyn Fn(Args) -> Out + Send + Sync> ───
71	// These use raw Arc construction for dyn trait object coercion.
72	
73	/// Constructor for `Callback<dyn Fn(Args) -> Out + Send + Sync>`.
74	impl<Args: 'static, Out: 'static> Callback<dyn Fn(Args) -> Out + Send + Sync> {
75	    /// Creates a new callback wrapping the given closure.
76	    pub fn new(f: impl Fn(Args) -> Out + Send + Sync + 'static) -> Self {
77	        Self(Arc::new(f))
78	    }
79	}
80	
81	impl<F: Fn(Args) -> Out + Send + Sync + 'static, Args: 'static, Out: 'static> From<F>
82	    for Callback<dyn Fn(Args) -> Out + Send + Sync>
83	{
84	    fn from(f: F) -> Self {
85	        Callback(Arc::new(f))
86	    }
87	}
88	
89	// ── Constructors for Callback<dyn for<'a> Fn(&'a T) -> Out + Send + Sync> ─
90	// The generic `Callback::new` requires `Args: 'static`, which excludes
91	// `&T` (since the reference itself is not `'static`). This sibling
92	// constructor accepts a higher-ranked closure over a reference argument
93	// so predicate-style Props fields (e.g. `Calendar::is_date_unavailable`)
94	// can still use `Callback` without falling back to raw `fn` pointers.
95	
96	/// Constructor for `Callback<dyn for<'a> Fn(&'a T) -> Out + Send + Sync>`.
97	impl<T: ?Sized + 'static, Out: 'static> Callback<dyn for<'a> Fn(&'a T) -> Out + Send + Sync> {
98	    /// Creates a new callback wrapping a higher-ranked closure over a
99	    /// reference argument.
100	    ///
101	    /// Use when the closure signature is `Fn(&T) -> Out` (predicates,
102	    /// transformers, key extractors) — the regular [`Callback::new`]
103	    /// constructor cannot satisfy the implicit HRTB lifetime because its
104	    /// `Args: 'static` bound excludes reference types.
105	    pub fn new_ref(f: impl for<'a> Fn(&'a T) -> Out + Send + Sync + 'static) -> Self {
106	        Self(Arc::new(f))
107	    }
108	}
109	
110	// ── Constructors for Callback<dyn Fn() + Send + Sync> (zero-argument) ─
111	// `dyn Fn() + Send + Sync` and `dyn Fn(Args) -> Out + Send + Sync` are
112	// distinct trait objects in Rust, so the generic `Callback::new` cannot
113	// produce `Callback<dyn Fn() + Send + Sync>`.
114	
115	/// Constructor for zero-argument `Callback<dyn Fn() + Send + Sync>`.
116	impl Callback<dyn Fn() + Send + Sync> {
117	    /// Creates a new zero-argument callback wrapping the given closure.
118	    pub fn new_void(f: impl Fn() + Send + Sync + 'static) -> Self {
119	        Self(Arc::new(f))
120	    }
121	}
122	
123	impl<F: Fn() + Send + Sync + 'static> From<F> for Callback<dyn Fn() + Send + Sync> {
124	    fn from(f: F) -> Self {
125	        Callback(Arc::new(f))
126	    }
127	}
128	
129	// ── Free function constructor ──────────────────────────────────────
130	
131	/// Ergonomic constructor for [`Callback`] with better type inference.
132	///
133	/// The compiler can infer `Args` from the closure signature without
134	/// requiring turbofish syntax.
135	pub fn callback<Args: 'static, Out: 'static>(
136	    f: impl Fn(Args) -> Out + Send + Sync + 'static,
137	) -> Callback<dyn Fn(Args) -> Out + Send + Sync> {
138	    Callback::new(f)
139	}
